use std::{
    fs,
    path::{Path, PathBuf},
    sync::mpsc,
};

use clap::Parser;
use glam::{Mat3, Vec3};
use image::{ImageBuffer, Rgba};
use serde::Deserialize;
use splatx::{
    camera::Camera,
    model::SplatxModel,
    renderer::{RenderTarget, Renderer, recommended_device_features},
};

#[derive(Debug, Parser)]
#[command(
    name = "render-image",
    about = "Render a splatx model to a PNG using a camera from JSON."
)]
struct Args {
    /// Input splatx NPZ model path.
    model: PathBuf,

    /// Camera JSON generated by tool/poses_bounds_npy_to_json.py.
    #[arg(long = "camera-json", value_name = "PATH")]
    camera_json: PathBuf,

    /// Output PNG path.
    #[arg(short, long, default_value = "output.png")]
    output: PathBuf,

    /// Camera id in the camera JSON.
    #[arg(long, default_value_t = 0)]
    camera_id: usize,

    /// Time parameter passed to the renderer.
    #[arg(short, long, default_value_t = 0.0)]
    time: f32,
}

#[derive(Debug, Deserialize)]
struct CameraSet {
    cameras: Vec<JsonCamera>,
}

#[derive(Debug, Deserialize)]
struct JsonCamera {
    id: usize,
    intrinsics: Intrinsics,
    bounds: Bounds,
    rotation: [[f32; 3]; 3],
    position: [f32; 3],
}

#[derive(Debug, Deserialize)]
struct Intrinsics {
    height: f32,
    width: f32,
    focal_length: f32,
}

#[derive(Debug, Deserialize)]
struct Bounds {
    near: f32,
    far: f32,
}

struct GpuContext {
    device: wgpu::Device,
    queue: wgpu::Queue,
}

impl JsonCamera {
    fn image_size(&self) -> (u32, u32) {
        (self.intrinsics.width(), self.intrinsics.height())
    }

    fn to_camera(&self) -> Camera {
        let position = Vec3::from_array(self.position);
        let rotation = Mat3::from_cols_array(&[
            self.rotation[0][0],
            self.rotation[1][0],
            self.rotation[2][0],
            self.rotation[0][1],
            self.rotation[1][1],
            self.rotation[2][1],
            self.rotation[0][2],
            self.rotation[1][2],
            self.rotation[2][2],
        ]);
        let forward = -(rotation * Vec3::Z);
        let up = rotation * Vec3::Y;
        let height = self.intrinsics.height();
        let fovy_radians = 2.0 * ((height as f32 * 0.5) / self.intrinsics.focal_length).atan();

        Camera {
            position,
            target: position + forward,
            up,
            fovy_radians,
            znear: self.bounds.near.max(0.001),
            zfar: self.bounds.far.max(self.bounds.near + 0.001),
        }
    }
}

impl Intrinsics {
    fn width(&self) -> u32 {
        round_dimension(self.width)
    }

    fn height(&self) -> u32 {
        round_dimension(self.height)
    }
}

fn main() -> Result<(), Box<dyn std::error::Error + Send + Sync>> {
    init_logger();

    let args = Args::parse();
    let model = load_model(&args.model)?;
    let json_camera = load_camera(&args.camera_json, args.camera_id)?;
    let camera = json_camera.to_camera();
    let (width, height) = json_camera.image_size();

    tracing::info!(
        model = %args.model.display(),
        camera_json = %args.camera_json.display(),
        camera_id = json_camera.id,
        width,
        height,
        time = args.time,
        "rendering image"
    );

    let gpu = pollster::block_on(create_gpu())?;
    let mut renderer = Renderer::new(&gpu.device, &gpu.queue, model);
    let pixels = render_image(&gpu, &mut renderer, &camera, args.time, width, height)?;
    write_png(&args.output, width, height, pixels)?;

    tracing::info!(output = %args.output.display(), "wrote image");
    Ok(())
}

fn load_model(path: &Path) -> Result<SplatxModel, Box<dyn std::error::Error + Send + Sync>> {
    tracing::info!(model = %path.display(), "loading model");
    SplatxModel::load_npz(path)
}

fn load_camera(
    path: &Path,
    camera_id: usize,
) -> Result<JsonCamera, Box<dyn std::error::Error + Send + Sync>> {
    tracing::info!(camera_json = %path.display(), camera_id, "loading camera");
    let text = fs::read_to_string(path)?;
    let cameras: CameraSet = serde_json::from_str(&text)?;
    cameras
        .cameras
        .into_iter()
        .find(|camera| camera.id == camera_id)
        .ok_or_else(|| format!("camera id {camera_id} not found").into())
}

async fn create_gpu() -> Result<GpuContext, String> {
    let instance = wgpu::Instance::default();
    let adapter = instance
        .request_adapter(&wgpu::RequestAdapterOptions {
            power_preference: wgpu::PowerPreference::HighPerformance,
            compatible_surface: None,
            force_fallback_adapter: false,
        })
        .await
        .map_err(|error| error.to_string())?;

    let required_features = recommended_device_features(&adapter);
    let (device, queue) = adapter
        .request_device(&wgpu::DeviceDescriptor {
            label: Some("splatx render-image device"),
            required_features,
            required_limits: wgpu::Limits::default(),
            experimental_features: wgpu::ExperimentalFeatures::disabled(),
            memory_hints: wgpu::MemoryHints::Performance,
            trace: wgpu::Trace::Off,
        })
        .await
        .map_err(|error| error.to_string())?;

    Ok(GpuContext { device, queue })
}

fn render_image(
    gpu: &GpuContext,
    renderer: &mut Renderer,
    camera: &Camera,
    time: f32,
    width: u32,
    height: u32,
) -> Result<Vec<u8>, Box<dyn std::error::Error + Send + Sync>> {
    let format = wgpu::TextureFormat::Rgba8UnormSrgb;
    let texture = gpu.device.create_texture(&wgpu::TextureDescriptor {
        label: Some("splatx render-image texture"),
        size: wgpu::Extent3d {
            width,
            height,
            depth_or_array_layers: 1,
        },
        mip_level_count: 1,
        sample_count: 1,
        dimension: wgpu::TextureDimension::D2,
        format,
        usage: wgpu::TextureUsages::RENDER_ATTACHMENT | wgpu::TextureUsages::COPY_SRC,
        view_formats: &[],
    });
    let view = texture.create_view(&wgpu::TextureViewDescriptor::default());

    let bytes_per_row = width * 4;
    let padded_bytes_per_row = align_to(bytes_per_row, wgpu::COPY_BYTES_PER_ROW_ALIGNMENT);
    let readback_size = padded_bytes_per_row as u64 * height as u64;
    let readback = gpu.device.create_buffer(&wgpu::BufferDescriptor {
        label: Some("splatx render-image readback"),
        size: readback_size,
        usage: wgpu::BufferUsages::COPY_DST | wgpu::BufferUsages::MAP_READ,
        mapped_at_creation: false,
    });

    let mut encoder = gpu
        .device
        .create_command_encoder(&wgpu::CommandEncoderDescriptor {
            label: Some("splatx render-image encoder"),
        });

    renderer.render(
        camera,
        time,
        RenderTarget {
            encoder: &mut encoder,
            queue: &gpu.queue,
            color_view: &view,
            format,
            width,
            height,
        },
    );
    renderer.analyze_visibility_buffers(&gpu.device, &mut encoder, time);

    encoder.copy_texture_to_buffer(
        wgpu::TexelCopyTextureInfo {
            texture: &texture,
            mip_level: 0,
            origin: wgpu::Origin3d::ZERO,
            aspect: wgpu::TextureAspect::All,
        },
        wgpu::TexelCopyBufferInfo {
            buffer: &readback,
            layout: wgpu::TexelCopyBufferLayout {
                offset: 0,
                bytes_per_row: Some(padded_bytes_per_row),
                rows_per_image: Some(height),
            },
        },
        wgpu::Extent3d {
            width,
            height,
            depth_or_array_layers: 1,
        },
    );

    gpu.queue.submit([encoder.finish()]);

    let (sender, receiver) = mpsc::channel();
    readback.map_async(wgpu::MapMode::Read, .., move |result| {
        let _ = sender.send(result);
    });
    gpu.device.poll(wgpu::PollType::wait_indefinitely())?;
    receiver.recv()??;

    let mapped = readback.get_mapped_range(..);
    let mut pixels = vec![0_u8; (bytes_per_row * height) as usize];
    for row in 0..height as usize {
        let src_offset = row * padded_bytes_per_row as usize;
        let dst_offset = row * bytes_per_row as usize;
        let src = &mapped[src_offset..src_offset + bytes_per_row as usize];
        let dst = &mut pixels[dst_offset..dst_offset + bytes_per_row as usize];
        dst.copy_from_slice(src);
    }
    drop(mapped);
    readback.unmap();

    Ok(pixels)
}

fn write_png(
    path: &Path,
    width: u32,
    height: u32,
    pixels: Vec<u8>,
) -> Result<(), Box<dyn std::error::Error + Send + Sync>> {
    let image = ImageBuffer::<Rgba<u8>, _>::from_raw(width, height, pixels)
        .ok_or("failed to create image buffer")?;
    image.save(path)?;
    Ok(())
}

fn round_dimension(value: f32) -> u32 {
    value.round().max(1.0).min(u32::MAX as f32) as u32
}

fn align_to(value: u32, alignment: u32) -> u32 {
    value.div_ceil(alignment) * alignment
}

fn init_logger() {
    tracing_subscriber::fmt()
        .with_max_level(tracing::Level::INFO)
        .init();
}
